```bash
awk 'BEGIN{repl="static bool planContainsAdditionalSimplifications(VPlan &Plan,
                                                  VPCostContext &CostCtx,
                                                  Loop *TheLoop) {
  (void)Plan; (void)CostCtx; (void)TheLoop;
  return true;
}
"} {if($0 ~ /^#ifndef NDEBUG/){print; inndef=1; next} if(inndef && $0 ~ /^static bool planContainsAdditionalSimplifications\(VPlan/){print repl; skip=1; next} if(skip && $0 ~ /^#endif/){print; skip=0; inndef=0; next} if(!skip) print }' /llvm-autofix-deps/llvm/llvm/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp > /tmp/LoopVectorize.cpp.fixed && mv /tmp/LoopVectorize.cpp.fixed /llvm-autofix-deps/llvm/llvm/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp && ninja -C /llvm-autofix/build/llvm-build/107015 && /llvm-autofix/build/llvm-build/107015/bin/opt -p loop-vectorize -S /tmp/test.ll
